INSERT INTO public.lessons (id,course_id,title,content_type,url,file_path,article_content,estimated_minutes,sort_order) VALUES
  ('a3e10900-0000-4000-8000-000000000000','a3e00000-0000-4000-8000-000000000000','確認テスト ─ 経営戦略の策定','quiz',NULL,NULL,NULL,3,2),
  ('a3e20900-0000-4000-8000-000000000000','a3e00000-0000-4000-8000-000000000000','確認テスト ─ M&A戦略','quiz',NULL,NULL,NULL,3,4),
  ('a3e30900-0000-4000-8000-000000000000','a3e00000-0000-4000-8000-000000000000','確認テスト ─ アライアンス・提携戦略','quiz',NULL,NULL,NULL,3,6),
  ('a3e40900-0000-4000-8000-000000000000','a3e00000-0000-4000-8000-000000000000','確認テスト ─ デジタル戦略・AI戦略','quiz',NULL,NULL,NULL,3,8)
INSERT INTO public.quiz_questions (lesson_id,question,option_a,option_b,option_c,option_d,correct_option,sort_order) VALUES
('a3e10900-0000-4000-8000-000000000000','本文が定める経営戦略の本質は、次のどれか。','各事業の戦略を集めて綴じ、全社戦略とすること','「どこで戦うか」と「どう勝つか」を、一本の線でつなぐこと','すべての事業に資源を平等に配分すること','一つの事業で競合にどう勝つかを磨き続けること','B',0),
('a3e10900-0000-4000-8000-000000000000','本文で、各事業の戦略を足し合わせても全社戦略にならない理由として挙げられているものは、どれか。','各事業が「どう勝つか」を磨くこと自体が誤りだから','足し算では、事業と事業の「あいだ」が見えないから','全社の視点より現場の視点のほうが常に正しいから','資源が有限で、どの事業も中途半端になるから','B',1),
('a3e10900-0000-4000-8000-000000000000','本文の型で、資源配分(ステップ3)の本体として述べられているものは、どれか。','畳む事業から資源を引き上げ、伸ばす事業へ移すこと','すべての事業を現状維持で安定して回すこと','今いちばん儲かっている事業に厚く張り続けること','乗り出す候補に、最初から最も厚く賭けること','A',2),
('a3e20900-0000-4000-8000-000000000000','本文が一行で言い切るM&Aの本質は、次のどれか。','買えば大きくなる、成長そのものである','数字のいい会社を安く手に入れる技術である','戦略の目的を、時間をお金で買って満たす手段である','文化のなじむ会社と一つになることである','C',0),
('a3e20900-0000-4000-8000-000000000000','本文で、買収が満たしうる目的として挙げられている四つに含まれないものは、どれか。','時間を買う','場所を買う','能力を買う','信用を買う','D',1),
('a3e20900-0000-4000-8000-000000000000','本文が、値段の上限(ステップ4)を交渉前に引く理由として述べていることは、どれか。','交渉が進むほど注いだ手間が惜しくなり、高く買いたくなるから','相手が必ず上限より低い額を提示してくるから','相乗りの価値は楽観的に大きく見積もるべきだから','上限を超えても目的を満たせば損はしないから','A',2),
('a3e30900-0000-4000-8000-000000000000','本文が一行で言うアライアンスの本質は、次のどれか。','相手に頼りきり、相手なしでは回らない体になること','自律を手放さずに、相手の力とつながること','取られたくないものを一切渡さず、身構えること','有名な会社と組んで、その看板を借りること','B',0),
('a3e30900-0000-4000-8000-000000000000','本文で「命綱」と呼ばれているものは、どれか。','提携が切れたとき、自社が立ちゆかなくなる部分','相手に完全に任せてよい、物流や請求の事務','提携を結んだときに交わす、両社の握手と発表','相手の看板の大きさと、市場での知名度','A',1),
('a3e30900-0000-4000-8000-000000000000','本文が、抜け道(ステップ3)を組むときに作っておく理由として述べていることは、どれか。','相手を疑い、いつでも切れる備えをしておくため','縁起をかつぎ、別れを避けるため','出口が見えているから、入口で思いきって踏み込めるため','成果の配分を、相手より多く確保するため','C',2),
('a3e40900-0000-4000-8000-000000000000','本文が一行で言うAI戦略の本質は、次のどれか。','AIを道具として使い、今の作業を速く安くすること','最新のAIをいち早く導入し、乗り遅れないこと','AIを前提に、事業の構造を組み替えること','判断も顧客対応も、すべてAIに任せること','C',0),
('a3e40900-0000-4000-8000-000000000000','本文が示す人とAIの役割分担で、人が握るべきとされていることは、どれか。','大量に案を出し、要約し、データを整えること','決めること、感じること、責任を取ること','たたき台を作り、構成案を複数用意すること','過去の成功例を集め、並べること','B',1),
('a3e40900-0000-4000-8000-000000000000','本文が、ガードレール(ステップ4)について戒めていることは、どれか。','経営ではなく現場に、囲いの設計を丸投げすること','「禁止リスト」にして、現場を萎縮させ止めてしまうこと','機密情報や顧客名を、外部のAIに入れないこと','AIの答えを、一つの意見として人が最後に検めること','B',2);
